INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (905, 0, "シズルさまにエリコさま、\nどうかされたのですか？", 19050041, 0, 107611, 11, 1, 0, 0.5, 10);
