INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (943, 0, "ずいぶんと色々なものが流れているね。\nここがプールでないなら、\n魚が潜んでいそうだけど…", 19430025, 0, 122511, 11, 1, 0, 1, 7);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (943, "", "", 19430026, "", 0, 91, "", "", "", "");
