INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (944, 0, "こんなに人がいっぱいいる商機、\n見逃すわけにはいかないにゃ！", 19440038, 0, 107911, 11, 1, 0, 1, 10);
