INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (944, 0, "大丈夫にゃ。バレないように…\nってやばいにゃ！　見回りだにゃ！", 19440046, 0, 107911, 11, 1, 0, 0.5, 8);
