INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (945, 0.1, "45_yui_shy_in", 19450030, 0.1, 122611, 3, "45_yui_shy_loop", 1, "", 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (945, 0.1, "45_yui_shy_in", 19450031, 0.1, 1, 3, "45_yui_shy_loop", 1, "", 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (945, "", "vo_fpc_30504", 19450032, "", "vo_fpc", 21, 0, "", "", "");
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (945, 0, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 19450033, 0, 122611, 11, 1, 0, 1, 5);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (945, "", "", 19450034, "", 0, 91, "", "", "", "");
